import { parseRatingChanges } from './task12';

describe('parseRatingChanges', () => {
  it('parses rating changes', () => {
    const changes = parseRatingChanges('1:2:3:4-12:8', [1500, 1400, 1300, 1200], 20);
    expect(changes.length).toBe(4);
    expect(changes[0]).toBeGreaterThan(0);
    expect(changes[1]).toBeLessThan(0);
  });

  it('handles 2-player format', () => {
    const changes = parseRatingChanges('1:2-5:3', [1500, 1400], 20);
    expect(changes.length).toBe(2);
  });
});
